### Configure Fixed Toolbar Item with Dropdown in Payload CMS Lexical Editor (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/custom-features.mdx

This TypeScript snippet demonstrates how to configure a custom toolbar item within a dropdown group for the fixed toolbar of a Payload CMS Lexical editor. It uses `createClientFeature` to define the feature, integrating a custom icon, a command dispatch on selection, and dynamic labeling. Dependencies include `@payloadcms/richtext-lexical` for core functionalities and custom node/plugin imports.

```ts
'use client'

import {
  createClientFeature,
  toolbarAddDropdownGroupWithItems,
} from '@payloadcms/richtext-lexical/client'
import { IconComponent } from './icon'
import { $isHorizontalRuleNode } from './nodes/MyNode'
import { INSERT_MYNODE_COMMAND } from './plugin'
import { $isNodeSelection } from '@payloadcms/richtext-lexical/lexical'

export const MyClientFeature = createClientFeature({
  toolbarFixed: {
    groups: [
      toolbarAddDropdownGroupWithItems([
        {
          ChildComponent: IconComponent,
          isActive: ({ selection }) => {
            if (!$isNodeSelection(selection) || !selection.getNodes().length) {
              return false
            }

            const firstNode = selection.getNodes()[0]
            return $isHorizontalRuleNode(firstNode)
          },
          key: 'myNode',
          label: ({ i18n }) => {
            return i18n.t('lexical:myFeature:label')
          },
          onSelect: ({ editor }) => {
            editor.dispatchCommand(INSERT_MYNODE_COMMAND, undefined)
          },
        },
      ]),
    ],
  },
})
```

